namespace ZuraTDD;

/// <summary>
///  dependencies class auto-generated for each test case class.
/// It stores all dependencies used by the test case mapped by their names.
/// </summary>
public interface ITestSubjectDependencies
{
	/// <summary>
	/// An indexer returning a dependency by its name.
	/// </summary>
	object this[string dependencyName] { get; }
}
